			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY2 =

		{

			TEXT = STR_ID_18635, --하거스 촌장님에게 반성문을 써준 윌리엄이, 나름 꾀를 부려 하거스 촌장님이 없는 여기 엘더로 온 것 같군요.

