			--MIRROR_VERTICAL = TRUE,

		},



		TEXT_PLAY0 =

		{

			TEXT = STR_ID_18637, --우리도 반성문을 받을 까요? 장난꾸러기에겐 가끔씩 따끔한 매가 약이 되죠. 하하하.

