			TAG_LEFT = FALSE,

		},

		TEXT_PLAY2 =

		{

			TEXT = STR_ID_12274,  -- 무라마사는 검에 자신의 사념을 주입하여 검이 원할 만큼 충분히 강하지 않은 주인이라면 무기로서 사용을 할 수 없도록 했는데,

