			TAG_LEFT = FALSE,

		},
		TEXT_PLAY5 =

		{

			TEXT = STR_ID_12277,  -- 지금!!  엘리오스의 대장장이들이 갑자기 흥분하기 시작했다. 봉인된 ‘무라마사’가 발견 된 것이 그 이유! 

			--WAIT = 1.0,

			TAG_NAME = STR_ID_12120,

			TAG_LEFT = FALSE,

		},
		TEXT_PLAY6 =

		{

			TEXT = STR_ID_12278,  -- 하지만 이들은 강함을 가지고 있지 못하므로 무라마사의 봉인을 풀 수 없다. 강함을 증명하고 ‘무라마사의 주인’이 되어라.


			--WAIT = 1.0,

			TAG_NAME = STR_ID_12120,

			TAG_LEFT = FALSE,

		},		
	},

}

