			PLAYER_TEXT1 = STR_ID_12280, -- 겨우 이 정도 였던가? 

			PLAYER_TEXT2 = STR_ID_12281, -- 이 걸로 증명이 된 건가요?

			PLAYER_TEXT3 = STR_ID_12282, -- 전설의 검이라... 너무 쉬운 도전이 아니었나?

			PLAYER_TEXT4 = STR_ID_12283, -- 이 정도의 증명은 말 그대로 '식은 죽 먹기'입니다.
			
			PLAYER_TEXT5 = STR_ID_12284, -- 이 정도로 나를 테스트 하려 들다니! 세이커 가문의 비밀무기에 견줄 수 도 없을 것 같군!

