			TEXT = STR_ID_12285,   -- (봉인된 무라마사가 공명하기 시작했다.)
			--WAIT = 1.0,
			TAG_NAME = STR_ID_12271,  -- '무라마사'의 음성   
			TAG_LEFT = FALSE,
		},	
		TEXT_PLAY2 =
		{
			TEXT = STR_ID_12286,   -- 그대의 강함은 잘 보았다. 그러나, 누가 이 정도로 해제되도록 봉인을 한지 모르겠다만...
			--WAIT = 1.0,
			TAG_NAME = STR_ID_12271,  -- '무라마사'의 음성   
			TAG_LEFT = FALSE,
		},	
		TEXT_PLAY3 =
		{
			TEXT = STR_ID_12287,   -- 나의 주인이 될 자격에 대해서는 충분한 증명이 되었다고는 생각지 않는다...
			--WAIT = 1.0,
			TAG_NAME = STR_ID_12271,  -- '무라마사'의 음성   
			TAG_LEFT = FALSE,
		},	
		TEXT_PLAY4 =
		{
			TEXT = STR_ID_12288,   -- 정녕 원한다면, 나를 다루어 보아라! 하지만, 그에 따른 모든 일들은 네 스스로 감당해야 할 것이다!!
			--WAIT = 1.0,
			TAG_NAME = STR_ID_12271,  -- '무라마사'의 음성   
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY5 =
		{
			PLAYER_TEXT0 = STR_ID_12289, -- 쳇! 건방떨긴... 원한다면 더 강한 모습도 보여줄 수 있다구!!
			
			PLAYER_TEXT1 = STR_ID_12290, -- 건방진 무기구나... 하지만, 호기심을 자극하긴 하는 걸~

			PLAYER_TEXT2 = STR_ID_12291, -- 찜찜하긴 하지만, 모험가라면 이런 무기도 한 번 쯤은 써볼 가치가 있겠군요.

			PLAYER_TEXT3 = STR_ID_12292, -- 그래, 나도 너를 한 번 검증해 보아야겠군...

			PLAYER_TEXT4 = STR_ID_12293, -- 얼마나 대단한 검이길래, 스스로 이런 건방진 모습을 보이는 거죠?
			
			PLAYER_TEXT5 = STR_ID_12294, -- 너의 수준이 우리 세이커 가문의 비기에 비해 얼마나 대단한지는 나도 궁금해! 밝혀보겠어!

			--WAIT = 1.0,

			TAG_LEFT = TRUE,		
		},
	},	
}

