-- 필드 수정 : 21729_02 마족총출동 완료를 21730_2 까지 다 흡수하여 수정하였다.
g_pEventScene:AddEventScene_LUA
{
	EVENT_SCENE_ID = "21720_02",
	EVENT_SEQUENCE0 =
	{
		SCENE_OBJECT_PLAY0 =
		{
			SCENE_OBJECT_NAME = "PENENSIO",
			ANIM_NAME = "Wait",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			START_POSITION = SCENE_OBJECT_POSITION["OP_RIGHT_SCREEN_OUT"],
			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_RIGHT_POS"], 0.0, 0.8},
			MIRROR_VERTICAL = TRUE,
		},

		TEXT_PLAY0 =
		{
			TEXT = STR_ID_12816,  -- 역시 대단하십니다. 하지만 마족들에게서 물의 인장의 흔적을 찾을 수 없는 것은…\n이미 란의 손에 물의 인장이 넘어가 버린 것 같습니다.\n서둘러야 겠습니다.
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
	},	
	EVENT_SEQUENCE1 =   						-- 플레이어 옵션
	{
		SCENE_OBJECT_PLAY0 =
		{
			SCENE_OBJECT_NAME = "PLAYER",
			ANIM_NAME = "Wait",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			START_POSITION = SCENE_OBJECT_POSITION["OP_LEFT_SCREEN_OUT"],
			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_LEFT_POS"], 0.0, 0.6},
			MIRROR_VERTICAL = TRUE,
		},
		TEXT_PLAY0 =
		{
			PLAYER_TEXT0 = STR_ID_12817,    -- 그런데, 신전에는 마족들만 있는 것 같지는 않았는걸요? 이상한 녀석들이 방해했어요. 마치… 붉은 기사단 같기도 했는데…
			PLAYER_TEXT1 = STR_ID_12818,    -- 아! 신전에는 마족들만 있지는 않았어요! 분명하지는 않았지만… 마치 붉은 기사단을 본 기분이었는데…
			PLAYER_TEXT2 = STR_ID_12819,    -- 그런데… 신전에는… 아마 제가 제대로 보았다면, 붉은 기사단원들이 있었습니다. 그것도 평소의 모습이 아닌 모습으로...
			PLAYER_TEXT3 = STR_ID_12820,    -- 아참, 내가 이상한 것을 보았는데… 아마도 붉은 기사단원들이었을거다. 하지만 속은 그것이 아닌 것 같더군.
			PLAYER_TEXT4 = STR_ID_12821,    -- 신전의 마족을 정리하면서 이상한 것을 보았습니다. 붉은 기사단원의 행색을 하고 있었지만… 느낌이 달랐습니다.
			PLAYER_TEXT5 = STR_ID_12822,    -- 아아… 신전 주변의 마족들과 대치하다가 뭔갈 보았어요. 잘못 본 것일까요?\n붉은 기사단원들이 마족들과 함께 있는 듯한 그 모습은...
