		},
		TEXT_PLAY1 =
		{
			TEXT = STR_ID_12861,  -- 내용이 무엇입니까??
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
	},
	EVENT_SEQUENCE1 =           -- 기계장치를 통해 나오는 헬퍼드의 환영  --*****
	{
		TEXT_PLAY0 =
		{
			TEXT = STR_ID_12862,   -- 이 편지를 누군가 보고 있다는 것은… 이미 제가 마족의 편에 있다는 것을 의미하겠군요.\n마족의 편에 서 있지만, 어둠의 백작 란의 함정은 그 어떠한 것 보다 가혹하게 저를 시험에 들게 하는군요.
			TAG_NAME = STR_ID_13477,
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY1 =
		{
			TEXT = STR_ID_12863,   -- 이 편지를 쓰고 있는 지금도, 제 선택이 옳은 것이라고 말할 수는 없습니다.\n하지만 몇 번을 생각해도 제 아들의 목숨을 쥐고 있는 란으로부터 벗어날 길이 없더군요.
			TAG_NAME = STR_ID_13477,
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY2 =
		{
			TEXT = STR_ID_12864,   -- 그리고 내 아들에게 상처를 주겠지만, 이것이 란으로부터 어린 아들놈을 구하는 유일한 길이 될 것 같습니다.
			TAG_NAME = STR_ID_13477,
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY3 =
		{
			TEXT = STR_ID_12865,   -- 어둠의 백작 란은 물의 신녀로부터 엘의 여인의 위치를 알아내기 위해서 하멜을 침공했습니다.\n만약 마족들이 엘의 여인으로부터 엘의 힘을 흡수하게 된다면, 그 어떤 강자라고 해도 막아내기 힘들게 될 것입니다.
			TAG_NAME = STR_ID_13477,
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY4 =
		{
			TEXT = STR_ID_12866,   -- 분명, 이 편지를 발견하신 분이 저보다 강한 의지와 힘을 가진 분이라 믿어 의심치 않습니다.\n란으로부터 하멜과 물의 신녀를 구해 위기에 빠진 하멜과 세상을 구해 주십시오.
			TAG_NAME = STR_ID_13477,
			TAG_LEFT = FALSE,
		},
	},
	
	EVENT_SEQUENCE2 =
	{
		SCENE_OBJECT_PLAY0 =
		{
			SCENE_OBJECT_NAME = "PENENSIO",
			ANIM_NAME = "Surprise",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			MIRROR_VERTICAL = TRUE,
		},
		TEXT_PLAY0 =
		{
			TEXT = STR_ID_12867,  -- 이, 이럴 수가…
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY1 =
		{
			TEXT = STR_ID_12868,  -- 당황하지 말드라고…
			TAG_NAME = STR_ID_10410,
			TAG_LEFT = TRUE,
		},
		TEXT_PLAY2 =
		{
			TEXT = STR_ID_12869,  -- 어떻게 하면 좋을까요? 무엇부터 시작해야 할 지 혼란스럽습니다.
			TAG_NAME = STR_ID_10409,
