			TEXT = STR_ID_12885,  -- 이제와서 방법을 찾을 수는 없구먼!\n마족들을 때려 눕히고 란을 막아야 문제가 해결되는 것이구먼.\n가끔은 무식하게 힘으로 밀어붙일 필요가 있지.
