			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_RIGHT_POS"], 0.0, 0.8},
			MIRROR_VERTICAL = TRUE,
		},
		SCENE_OBJECT_PLAY1 =
		{
			SCENE_OBJECT_NAME = "SHASHA",
			ANIM_NAME = "Wait",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			START_POSITION = SCENE_OBJECT_POSITION["OP_LEFT_POS"],
			MIRROR_VERTICAL = TRUE,
		},
		TEXT_PLAY0 =
		{
			TEXT = STR_ID_12921,  -- 신녀님… 어둠의 구슬 속에 있으실 때를 기억하십니까?\n잠시지만 어둠을 만나는 북쪽의 불의 땅…\n이런 이야기를 하셨던 것 같습니다만…
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY1 =
		{
			TEXT = STR_ID_12922,  -- 잘은 기억이 나지 않지만… 란이 무엇을 찾고 싶어했는지 알고 있어요...\n대대로 엘의 힘을 숭배하는 신녀들은 엘의 여인과 공명하게 되어있으니…
			TAG_NAME = STR_ID_12934,
			TAG_LEFT = TRUE,
		},
		TEXT_PLAY2 =
		{
			TEXT = STR_ID_12923,  -- 제가 말했던 것은 엘의 여인이 환생한 곳의 정보일 거에요.
			TAG_NAME = STR_ID_12934,
			TAG_LEFT = TRUE,
		},
		TEXT_PLAY3 =
		{
			TEXT = STR_ID_12924,  -- 어쩌면…
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
	},
	EVENT_SEQUENCE1 =
	{
		SCENE_OBJECT_PLAY1 =
		{
			SCENE_OBJECT_NAME = "SHASHA",
			ANIM_NAME = "Sad",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			MIRROR_VERTICAL = TRUE,
		},
		TEXT_PLAY0 =
		{
			TEXT = STR_ID_12925,  -- (??)
			TAG_NAME = STR_ID_12934,
			TAG_LEFT = TRUE,
		},
		TEXT_PLAY1 =
		{
			TEXT = STR_ID_12926,  -- 물의 신녀님께서 이야기를 한 직후 란 과의 전투에서 승리할 수 있었습니다.\n백작은 필요한 정보를 얻었으니 전투에서 패한 척하며 이 곳에서 빠져나간 것은 아닌가 라는 생각이 드는군요.
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
	},
	EVENT_SEQUENCE2 =
	{
		SCENE_OBJECT_PLAY1 =
		{
			SCENE_OBJECT_NAME = "SHASHA",
			ANIM_NAME = "Wait",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			MIRROR_VERTICAL = TRUE,
		},
		TEXT_PLAY0 =
		{
			TEXT = STR_ID_12927,  -- 너무 걱정하지는 마세요… 제가 말했던 정보로는 모든 것을 알 수가 없답니다.\n다른 모든 신녀님들의 진언이 합쳐지는 순간 비로써 엘의 여인이 있는 곳에 당도할 수 있게 될 테니까요...
			TAG_NAME = STR_ID_12934,
			TAG_LEFT = TRUE,
		},
		TEXT_PLAY1 =
		{
			TEXT = STR_ID_12928,  -- 분명 마족들은 다른 엘의 신녀님을 찾아갔을 거에요.
			TAG_NAME = STR_ID_12934,
			TAG_LEFT = TRUE,
		},
		TEXT_PLAY2 =
		{
			TEXT = STR_ID_12929,  -- 그렇군요… 그렇다면 하멜은 위기에서 벗어났다고 생각할 수 있겠네요.\n하지만 이 모든 것이 잠깐의 평화일 것이라는 생각이 듭니다.
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
	},
	EVENT_SEQUENCE3 =
	{
		SCENE_OBJECT_PLAY0 =
		{
			SCENE_OBJECT_NAME = "PLAYER",
			ANIM_NAME = "Wait",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			START_POSITION = SCENE_OBJECT_POSITION["OP_LEFT_SCREEN_OUT"],
			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_LEFT_POS"], 0.0, 0.8},
			MIRROR_VERTICAL = TRUE,
		},
		SCENE_OBJECT_PLAY1 =
		{
			SCENE_OBJECT_NAME = "SHASHA",
			ANIM_NAME = "Wait",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			START_POSITION = SCENE_OBJECT_POSITION["OP_LEFT_POS"],
			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_LEFT_SCREEN_OUT"], 0.0, 0.8},
			MIRROR_VERTICAL = TRUE,
		},
		TEXT_PLAY0 =
		{
			HIDE_TEXT_BOX = TRUE,
			WAIT = 0.5,
		},
	},	
	EVENT_SEQUENCE4 =
	{
		SCENE_OBJECT_PLAY0 =								
		{
			SCENE_OBJECT_NAME = "PENENSIO",
			ANIM_NAME = "Smile",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			MIRROR_VERTICAL = TRUE,
		},
		TEXT_PLAY0 =
		{
			TEXT = STR_ID_12931,  -- 저희는 이제 이 곳의 일을 마무리하는데로 벨더로 돌아가고자 합니다.
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY1 =
		{
			TEXT = STR_ID_12932,  -- 엘 수색대에서 시작해서 모험을 계속 이어나가신다고 들었습니다.\n너무나 대단하고 장한 일을 하고 계신 것 같습니다.
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
		TEXT_PLAY2 =
		{
			TEXT = STR_ID_12933,  -- 어려운 부탁이지만 이 모험을 계속 이어 다음 신녀님께서 마족에게 신탁을 빼앗기는 것을 저지해 주셨으면 합니다.\n행운을 빕니다.
			TAG_NAME = STR_ID_10409,
			TAG_LEFT = FALSE,
		},
