		},



		TEXT_PLAY0 =

		{

			TEXT = STR_ID_13697,		-- 안녕! 너 혹시 공식대전에 관심있어? 해본 적은 있어?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1860,

			TAG_LEFT = FALSE,

		},

		TEXT_PLAY1 =

		{

			TEXT = STR_ID_13698,		-- 공식대전이란 '대전'버튼을 누르고 신청하기만 누르면 자동으로 대전을 시작할 수 있는 방식이야!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1860,

			TAG_LEFT = FALSE,

		},

		TEXT_PLAY2 =

		{

			TEXT = STR_ID_13699,		-- 물론, 지금 대전을 하고 싶은 사람 중에 나와 가장 비슷한 실력을 지닌 사람과 매칭을 시켜주지!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1860,

			TAG_LEFT = FALSE,

		},

		TEXT_PLAY3 =

		{

			TEXT = STR_ID_13700,		-- 만약, 매일매일 공식대전으로 데스매치를 하고, 두 번만 이기고 온다면 내가 보상을 주려고해! 관심있어?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1860,

			TAG_LEFT = FALSE,

		},

	},

}

