			TEXT = STR_ID_13703,		-- AP는 공식대전을 통해 모을 수 있고, 장비 아이템이나 마법석, 강화석, 물약 같은 모험에 유용한 아이템을 살 수 있어! (물론 내가 팔고 있어.)

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1860,

			TAG_LEFT = FALSE,

