			--WAIT = 1.0,

			TAG_NAME = STR_ID_370,

			TAG_LEFT = FALSE,

		},
		TEXT_PLAY4 =

		{

			TEXT = STR_ID_14617  , -- 몬스터 파티 큐브는 모양은 으시시하지만 귀엽고, 능력은 어마어마한 액세서리를 주는 큐브인 것 알고 계신가요?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_370,

			TAG_LEFT = FALSE,

		},
		TEXT_PLAY5 =

		{

			TEXT = STR_ID_14618  , -- 저주받은 뼈조각은 '15개를 모으면 언데드 스피릿이라는 아바타를 제조할 수 있는 아이템'이랍니다.

