		},

		TEXT_PLAY0 =

		{

			TEXT = STR_ID_18298,	--자…여기…마무리가 된 것 같은데…역시…나소드의 합금 쉴드 정도로는 화염핵의 기운을 견디지 못하네 퐁…

			--WAIT = 1.0,

