			MIRROR_VERTICAL = TRUE,

		},

		TEXT_PLAY0 =

		{

			TEXT = STR_ID_18300,	--음! 방법이 있지 퐁! 페이타의 렌토가 마족으로부터 특수한 금속을 재련하는 방법을 알고 있어. 서둘러 그에게 가보는게 좋겠어 퐁! 미리 연락해놓을께 퐁!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1850,

			TAG_LEFT = FALSE,

		},

	},

}

