--베테랑 커맨더 (Veteran Commander) 5/5

g_pEventScene:AddEventScene_LUA

{

	EVENT_SCENE_ID = "35124_01",

	EVENT_SEQUENCE0 =

	{

		SCENE_OBJECT_PLAY0 =

		{

			SCENE_OBJECT_NAME = "LENTO",

			ANIM_NAME = "Angry",

			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],

			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3

			START_POSITION = SCENE_OBJECT_POSITION["OP_RIGHT_SCREEN_OUT"],

			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_RIGHT_POS"], 0.0, 0.8},

			MIRROR_VERTICAL = FALSE,

		},



		TEXT_PLAY0 =

		{

			TEXT = STR_ID_18302,	--봅시다…이런…..이렇게 까지 나소드 팔의 힘을 키우려는 겁니까? 당신을 위해서도! 세상을 위해서도 이건 좋지 않습니다!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1866,

			TAG_LEFT = FALSE,

		},

		TEXT_PLAY1 =

		{

			TEXT = STR_ID_18303,	--혹시라도 당신이 쓰러져 그 힘의 비결이 마족들에게 알려진다면 그 뒤는 누구도 무마할 수 없을 겁니다! 이런데도!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1866,

			TAG_LEFT = FALSE,

		},

		TEXT_PLAY2 =

		{

			TEXT = STR_ID_18304,	--…하..당신은 확고하군요. 좋습니다! 당신이니까 믿겠습니다! 그리고 그 소원..들어드리겠습니다! 꼭 제가 말한 재료를 구해오십시오! 그리고 꼭 살아 돌아 오십시오!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1866,

			TAG_LEFT = FALSE,

		},

	},

}

g_pEventScene:AddEventScene_LUA

{

	EVENT_SCENE_ID = "35124_02",

	EVENT_SEQUENCE0 =

	{

		SCENE_OBJECT_PLAY0 =

		{

			SCENE_OBJECT_NAME = "LENTO",

			ANIM_NAME = "Wait",

			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],

			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3

			START_POSITION = SCENE_OBJECT_POSITION["OP_RIGHT_SCREEN_OUT"],

			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_RIGHT_POS"], 0.0, 0.8},

			MIRROR_VERTICAL = FALSE,

		},



		TEXT_PLAY0 =

		{

			TEXT = STR_ID_18305,	--다크 스틸, 부유석… 모두 확실하군요. 자! 세상에 하나 뿐인 당신만의 나소드 팔이 완성되었습니다!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1866,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY1 =

		{

			TEXT = STR_ID_18306,	--당신의 전력을 쏟은 화염탄을 쓰더라도 그 팔은 견뎌내며, 당신을 더욱 자유롭게 움직이게 해줄 것입니다!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1866,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY2 =

		{

			TEXT = STR_ID_18307,	--다시 세상에 나갈 준비가 되셨습니까? 베테랑 커맨더! 당신은 엘리오스에서 가장 용맹한 용병으로 세상에 맹위를 떨칠 것입니다!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_1866,

			TAG_LEFT = FALSE,

		},

	},

}


