--명예 검투사(대전 시즌2 전야 이벤트)

g_pEventScene:AddEventScene_LUA
{
	EVENT_SCENE_ID = "40100_01",
	EVENT_SEQUENCE0 =
	{
		SCENE_OBJECT_PLAY0 =
		{
			SCENE_OBJECT_NAME = "CAMILLA",
			ANIM_NAME = "Smile",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			START_POSITION = SCENE_OBJECT_POSITION["OP_RIGHT_SCREEN_OUT"],
			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_RIGHT_POS"], 0.0, 0.8},
			MIRROR_VERTICAL = FALSE,
		},
		TEXT_PLAY0 =
		{
			TEXT = STR_ID_18694,	--야호! 소식 들었어? 9월 20일에 대전 시즌2가 업데이트 된다고 해! 어떤 변화가 생길지 궁금하지 않아? 그지?
			--WAIT = 1.0,
			TAG_NAME = STR_ID_1860,
			TAG_LEFT = FALSE,
		},
		
		TEXT_PLAY1 =
		{
			TEXT = STR_ID_18695,	--이번 대전 시즌2에는 말야! 완전히 새로워진 대전 장비를 공짜로....어? 히히히 말하지 말랬는데. 히히히히
			--WAIT = 1.0,
			TAG_NAME = STR_ID_1860,
			TAG_LEFT = FALSE,
		},
		
		TEXT_PLAY2 =
		{
			TEXT = STR_ID_18696,	--뭐, 조금만 기다려봐. 곧 정보가 나올테니까. 기대해도 좋을거야. 나도 곧 엄청 바빠지겠는걸?!
			--WAIT = 1.0,
			TAG_NAME = STR_ID_1860,
			TAG_LEFT = FALSE,
		},
		
		TEXT_PLAY3 =
		{
			TEXT = STR_ID_18697,	--이번 시즌을 마무리하면서 대전에서 노력해온 용맹한 용사들을 위해 명예를 선물하기로 했어. 이 교관님이 말이야. 엣헴! 
			--WAIT = 1.0,
			TAG_NAME = STR_ID_1860,
			TAG_LEFT = FALSE,
		},
		
		TEXT_PLAY4 =
		{
			TEXT = STR_ID_18698,	--공식 대전에서 네가 충분히 명예를 가질 자격이 있는지 확인해보겠어! 힘내! 난 네 편인 거 알지?
			--WAIT = 1.0,
			TAG_NAME = STR_ID_1860,
			TAG_LEFT = FALSE,
		},
	},	
}

