--엘의 폭발 경보(1/2)	--//공존의 축제 2012-10-14,

g_pEventScene:AddEventScene_LUA

{

	EVENT_SCENE_ID = "40130_01",

	EVENT_SEQUENCE0 =

	{

		SCENE_OBJECT_PLAY0 =

		{

			SCENE_OBJECT_NAME = "ARIEL",

			ANIM_NAME = "Surprise",

			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],

			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3

			START_POSITION = SCENE_OBJECT_POSITION["OP_RIGHT_SCREEN_OUT"],

			MOVE_POSITION = {SCENE_OBJECT_POSITION["OP_RIGHT_POS"], 0.0, 0.8},

			MIRROR_VERTICAL = FALSE,

		},



		TEXT_PLAY0 =

		{

			TEXT = STR_ID_19162,     --겪으셨을지 모르겠지만 곳곳에 지진이 일어나고 있답니다. 저희 코보에서 알아낸 정보에 의하면 '다크엘' 이 원인이라고 해요.

			--WAIT = 1.0,

			TAG_NAME = STR_ID_370,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY1 =

		{

			TEXT = STR_ID_19163,     --공존의 축제에는 엘의 기운이 가장 강해지는 날 입니다. 마족에 의해 강대해진 다크엘의 기운이 공존의 축제에 더 강해지면서

			--WAIT = 1.0,

			TAG_NAME = STR_ID_370,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY2 =

		{

			TEXT = STR_ID_19164,     --엘의 힘과 공명하게 됐습니다. 결국 세계에 흩어진 엘들이 불안정해지며 폭발을 일으키고 있고 그 폭발이 지각 변동을 일으키고 있는 것 입니다. 

			--WAIT = 1.0,

			TAG_NAME = STR_ID_370,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY3 =

		{

			TEXT = STR_ID_19165,     --이대로라면 과거 공존의 축제의 대폭발이 재현될지도 모릅니다. 다크엘을 정화시켜 이 피해를 줄여야만 해요. 모험가님! 도와주시겠어요?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_370,

			TAG_LEFT = FALSE,

		},
	},
}

