			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY3 =

		{

			TEXT = STR_ID_22855,  -- 칼루소 부족은 바람의 힘을 이용 하는 부족, 그들이 베히모스 옆에 정착할 때… 수호자인 베히모스가 깨어나진 않을까 걱정했는데… 아무래도 그것과 바람의 신녀님이 연관이 있는듯 하구나!

