			TAG_NAME = STR_ID_22044,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY5 =

		{

			TEXT = STR_ID_22857,  -- 아니야, 카루 대추장은 한낱 마족에 휘둘릴 사람이 아니다… 자세한 사정은 칼루소 부족의 대추장인 카루에게 들으면 되겠지. 지체말고 파르고산의 칼루소 부족을 다녀오거라.

