	SCENE_OBJECT_PLAY0 =
		{
			SCENE_OBJECT_NAME = "EMIRATE",

			ANIM_NAME = "Wait",

			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],

