		},	
		
		TEXT_PLAY0 =

		{

			TEXT = STR_ID_22916,  -- 그건 내가 증명하지!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22042,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY1 =

		{

			TEXT = STR_ID_22917,  -- 애미리트…! 자네가 여길 어떻게!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_23056,

			TAG_LEFT = TRUE,
		},	
		
		TEXT_PLAY2 =

		{

			TEXT = STR_ID_22918,  -- 역시, 저번에 내가 마을에 방문했던 일을 기억하지 못하는군! 마족들에게 조종당하고 있던게 확실해졌어… 이게 무언지 알겠나? 하피들의 대장 켈라이노의 회색 깃털이다!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22042,

			TAG_LEFT = FALSE,
		},	
		
		TEXT_PLAY3 =

		{

			TEXT = STR_ID_22919,  -- 흠…! 저렇게 큰 회색 깃털은 켈라이노 밖에 가지고 있지 못해…! 그런데 그것과 이 일의 원흉이 마족이란것과 무슨… 관계가 있는 거지?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_23056,

			TAG_LEFT = TRUE,
		},	
		
		TEXT_PLAY4 =

		{

			TEXT = STR_ID_22920,  -- 바람의 엘의 기운을 오염시켜서 하피들을 불안하게하고 이성적인 판단이 흐려질만큼 혼란이 일었을 때, 켈라이노에게 나타나 신녀님을 납치해 바람의 엘의 기운을 진정시켜주겠다고 속인게 바로 그 마녀였소!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22042,

			TAG_LEFT = FALSE,
		},	
		
		TEXT_PLAY5 =

		{

			TEXT = STR_ID_22921,  -- 그것도 모자라 하피를 잡아 잔인하게 살해한 후, 우리 상단이 하피의 깃털을 다시 팔려 한다고 덮어씌웠지. 그일로 하피들과 큰 전쟁이 벌어질뻔 했소.

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22042,

			TAG_LEFT = FALSE,
		},	
		
		TEXT_PLAY6 =

		{

			TEXT = STR_ID_22922,  -- 하지만 여기 있는 이 모험가들의 활약 덕분에 켈라이노와의 오해를 풀고 모든 일의 원흉이 마족이란 것을 알게 되었지. 이 회색의 깃털은 그때, 켈라이노에게 받아둔 화해의 증표요,

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22042,

			TAG_LEFT = FALSE,
		},	
		
		TEXT_PLAY7 =

		{

			TEXT = STR_ID_22923,  -- 이번 샌더와 칼루소 부족간의 일또한 비슷하다고 생각하지 않소? 마녀 카리스의 이간질에 당해선 안됩니다!!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22042,

			TAG_LEFT = FALSE,
		},
	},
	
	EVENT_SEQUENCE10 =

	{

		SCENE_OBJECT_PLAY0 =

