			TAG_NAME = STR_ID_22044,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY2 =

		{

			TEXT = STR_ID_23031,  -- 로즈앙이 내게 선물이랍시고 준게 악몽으로 정신을 사납게 하는 반지라는건 이미 알고 있었단다!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY3 =

		{

			TEXT = STR_ID_23032,  -- 희귀한 악세서리라고 정체를 모를줄 알았겠지만… 엘의 기운을 연구하는 내가 모르는 아티펙트는 거의 없지! 호호…!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY4 =

		{

			TEXT = STR_ID_23033,  -- 게다가 내겐 저주같은게 통하지 않는단다…! 오히려 간단한 방법으로 시전자에게 되돌려 줄 수도 있지. 연금술 실험의 부작용으로 생긴 효과긴 하지만… 이럴 땐 참 유용하지

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY5 =

		{

			TEXT = STR_ID_23034,  -- 그런 것도 모르고 이걸 내게 선물하다니… 어리석은 로즈앙...! 호호! 일주일 정도 잠도 못자고 고생했을테니… 이제 그만 용서해 주기로 할까?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY6 =

		{

			TEXT = STR_ID_23035,  -- 저주를 풀려면 반지에 서린 기운을 중화시키면 된단다. 너도 이일에 일조를 한 듯 하니 결자해지 한다는 심정으로 날좀 도와주려므나.

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY7 =

		{

			TEXT = STR_ID_23036,  --기운을 중화시키는 촉매로는… 어디보자… 그래! 2번 필드와 트락소굴에서 나오는 트락의 피가 좋겠구나…! 어서 구해오거라.

