		TEXT_PLAY0 =

		{

			TEXT = STR_ID_26458,  -- 아니 넌? 칼루소 전투추장 베이가 아니냐? 무슨말인게야?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = TURE,

		},
		
		TEXT_PLAY1 =

		{

			TEXT = STR_ID_26459,  -- 헉헉… 족장님의 명으로 카리스를 추적중이었는데… 흔적을 쫓아 당도한 곳이 파르고산이었습니다. 수색을 하던중 산이 들썩거리며 마족들이 습격을 해와서…! 간신히 추격을 뿌리치고 오는길입니다.

			--WAIT = 1.0,

			TAG_NAME = STR_ID_26751,

			TAG_LEFT = FALSE,

		},
		
		TEXT_PLAY2 =

		{

			TEXT = STR_ID_26460,  -- 뭐라고!? 이런… 한발 늦었구나! 이미…! 베히모스가 마족들의 수중에 넘어간 모양이야! 

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = TRUE,

		},
		
		TEXT_PLAY3 =

		{

			TEXT = STR_ID_26461,  -- 이 일로 긴급하게 회담을 청하는 카루 대추장님의 전언이 있었습니다. 바람의 정령을 통해 칼루소 부족에 계신 대추장님과 대화를 직접 나눠보시죠….

			--WAIT = 1.0,

			TAG_NAME = STR_ID_26751,

			TAG_LEFT = FALSE,

		},
	},
	
	EVENT_SEQUENCE9 =
	
	{
		SCENE_OBJECT_PLAY0 =
		{
			SCENE_OBJECT_NAME = "KARU",
			ANIM_NAME = "Wait",
			PLAY_TYPE = XSKIN_ANIM_PLAYTYPE["XAP_LOOP"],
			PLAY_SPEED = 0.3,		-- 애니메이션 재생 속도, 기본값 0.3
			START_POSITION = SCENE_OBJECT_POSITION["OP_CENTER_POS"],
			MIRROR_VERTICAL = FALSE,
		},
		
		TEXT_PLAY0 =

		{

			TEXT = STR_ID_26462,  -- 바포르 할멈이구만! 날세 카루, 우리 칼루소 부족민들을 해방시켜준 영웅들도 함께 있구만! 카리스의 대군과 베히모스를 상대하기엔 우리의 전력이 부족하다네…!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_23056,

			TAG_LEFT = TURE,

		},
		
		TEXT_PLAY1 =

		{

			TEXT = STR_ID_26463,  -- 전력이라…! 부족하면 채우면 되겠지!  얼마전에… 바람의 유적지에서 거대한 배가 묻혀있는걸 발견했다는 소식이 발굴팀에서 전해졌다오, 

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = TRUE,

		},
		
		TEXT_PLAY2 =

		{

			TEXT = STR_ID_26464,  -- 내가 볼 땐 이것이 전설로만 전해오던 칼루소 부족의 고대 이동수단이라고 생각되는데…. 이것을 꺼내오는건 어떻겠나?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = TRUE,

		},
		
		TEXT_PLAY3 =

		{

			TEXT = STR_ID_26465,  -- 고대의 이동수단!? 설마... 칼루소 전설에 등장하는 날아다니는 배를 얘기하는겐가? 허… 잊혀진 전설로만 생각했거늘… 그것을 발견해 낸겐가…?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_23056,

			TAG_LEFT = TURE,

		},
		
		TEXT_PLAY4 =

		{

			TEXT = STR_ID_26466,  -- 그렇다네… 이땅에 살던 고대 칼루소인들이 바람의 힘을 이용해 하늘을 날아다녔다고 하는 '비공정' 얘길세, 발빠른 기술자들을 선별해서 유적을 발굴 중이네만… 한가지 문제가 있어!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = TRUE,

		},
		
		TEXT_PLAY5 =

		{

			TEXT = STR_ID_26467,  -- 동력기관은 멀쩡한데…  무엇보다 중요한 바람의 힘을 잃어버렸어, 동력부의 윈드스톤 교환이 필요하다네. 외형의 보수작업과 함께 윈드스톤의 보충을 맡아줄 수 있겠나?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = TRUE,

		},
		
		TEXT_PLAY6 =

		{

			TEXT = STR_ID_26468,  -- 으음…! 윈드스톤을 준비해줄 수 있네만… 작은 마을만 하다는 모선을 띄우는데는 대량의 윈드스톤이 필요하겠지! 비축분을 다 가져간다고 해도 모자랄게야…!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_23056,

			TAG_LEFT = TURE,

		},
		
		TEXT_PLAY7 =

		{

			TEXT = STR_ID_26469,  -- 모자라면 더 만들면 되는것 아닌가?

			--WAIT = 1.0,

			TAG_NAME = STR_ID_22044,

			TAG_LEFT = TRUE,

		},
		
		TEXT_PLAY8 =

		{

			TEXT = STR_ID_26470,  -- 아닐세… 그게 그렇게 쉬운문제가 아니야! 윈드스톤은 아무 돌에다가 바람의 힘만 집약시킨다고 만들어지는 물건이 아니야! 오랜 세월 바람을 맞고 풍화된 풍석이라고 하는 바람의 성질이 깃들기 쉬운 돌이 그 재료라네!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_23056,

			TAG_LEFT = TURE,

		},
		
		TEXT_PLAY9 =

		{

			TEXT = STR_ID_26471,  -- 칼루소 부족 마을을 띄우느라 대부분의 풍석은 이미 사용해버렸어… 비축량이 얼마 남지 않았다네!

			--WAIT = 1.0,

			TAG_NAME = STR_ID_23056,

			TAG_LEFT = TURE,

		},
	},
	
